import { secureStorage } from '../utils/encryptionUtils';
import { userProfileService } from './userProfileService';
import { paymentService } from './paymentService';
import { authService } from './authService';

export const secureDataService = {
  clearAllSecureData: async () => {
    try {
      await secureStorage.clear();
      return { success: true };
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  exportSecureData: async () => {
    try {
      const [userProfile, paymentInfo, tokens] = await Promise.all([
        userProfileService.getUserProfile(),
        paymentService.getPaymentInfo(),
        authService.getTokens(),
      ]);

      return {
        success: true,
        data: {
          userProfile: userProfile.data,
          paymentInfo: paymentInfo.data,
          tokens: tokens.data,
        },
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  importSecureData: async (data) => {
    try {
      const promises = [];

      if (data.userProfile) {
        promises.push(userProfileService.saveUserProfile(data.userProfile));
      }

      if (data.paymentInfo) {
        promises.push(paymentService.savePaymentInfo(data.paymentInfo));
      }

      if (data.tokens) {
        promises.push(
          authService.saveTokens(data.tokens.authToken, data.tokens.refreshToken)
        );
      }

      await Promise.all(promises);
      return { success: true };
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  getAllSecureKeys: async () => {
    try {
      const keys = await secureStorage.getAllKeys();
      return { success: true, data: keys };
    } catch (error) {
      return { success: false, error: error.message };
    }
  },
};

